import React, { useEffect, useState } from "react";

export default function HackerDashboard() {
  const [user, setUser] = useState(null);

  useEffect(() => {
    cuseEffect(() => {
  const role = localStorage.getItem("role");
  const token = localStorage.getItem("token");

  console.log("DASHBOARD STORAGE 👉", { role, token });

  setUser({ role, token });
}, []);

  }, []);

  return (
    <div className="min-h-screen bg-gray-100 p-8">
      <div className="max-w-4xl mx-auto">
        <h1 className="text-3xl font-bold mb-4">🧑‍💻 Hacker Dashboard</h1>

        <div className="bg-white rounded shadow p-6 mb-6">
          <p className="text-lg">
            <span className="font-semibold">Role:</span> {user?.role}
          </p>
          <p className="text-sm text-gray-500 break-all mt-2">
            <span className="font-semibold">JWT:</span> {user?.token}
          </p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <div className="bg-white p-4 rounded shadow">
            <h2 className="font-semibold">🐞 Submit Bug</h2>
            <p className="text-sm text-gray-600">Report a new vulnerability</p>
          </div>

          <div className="bg-white p-4 rounded shadow">
            <h2 className="font-semibold">📄 My Bugs</h2>
            <p className="text-sm text-gray-600">Track submitted bugs</p>
          </div>

          <div className="bg-white p-4 rounded shadow">
            <h2 className="font-semibold">💰 Wallet</h2>
            <p className="text-sm text-gray-600">View rewards & balance</p>
          </div>
        </div>

        <button
          className="mt-8 bg-red-500 text-white px-4 py-2 rounded"
          onClick={() => {
            localStorage.clear();
            window.location.href = "/";
          }}
        >
          Logout
        </button>
      </div>
    </div>
  );
}
